      $c.gus.cfEnableBtnOnly($p, [btn_Save, btn_Cancel, btn_1, btn_2, btn_7, btn_exChg, btn_cusChg, btn_AddRow1, btn_DelRow1, btn_DelAll1, btn_CancelRow1, btn_AddRow2, btn_DelRow2, btn_DelAll2, btn_CancelRow2, btn_AddRow3, btn_DelRow3, btn_DelAll3, btn_CancelRow3, pu_ResultdateChange]);
